import React, { useState, useEffect, useRef } from 'react';

const ChatWidget: React.FC = () => {
  const [chatOpen, setChatOpen] = useState(false);
  const [messages, setMessages] = useState([
    { from: 'admin', text: '애드모어 반갑습니다!\n상담 운영 시간 안내\n· 평일 10:00 ~ 17:00\n· 주말, 공휴일 휴무\n순차적으로 확인하여 답변드리도록 하겠습니다.' }
  ]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatOpen && chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, chatOpen]);

  const handleSend = () => {
    if (!input.trim()) return;
    setMessages(msgs => [...msgs, { from: 'user', text: input }]);
    setInput('');
    setTimeout(() => {
      setMessages(msgs => [...msgs, { from: 'admin', text: '상담 운영팀이 곧 답변드리겠습니다.' }]);
    }, 1200);
  };

  return (
    <>
      {/* 문의하기 플로팅 버튼 */}
      <button
        className="fixed bottom-6 right-6 z-50 bg-blue-600 text-white rounded-full shadow-lg w-16 h-16 flex items-center justify-center text-3xl hover:bg-blue-700 transition"
        onClick={() => setChatOpen(true)}
        aria-label="문의하기"
        style={{ boxShadow: '0 4px 24px rgba(0,0,0,0.15)' }}
      >
        <span>💬</span>
      </button>
      {/* 문의하기 채팅 위젯 모달 */}
      {chatOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-end bg-black/10">
          <div className="w-full max-w-sm bg-white rounded-2xl shadow-2xl m-6 flex flex-col" style={{ height: '540px' }}>
            {/* 상단바 */}
            <div className="flex items-center justify-between px-4 py-3 border-b">
              <div className="flex items-center">
                <div className="w-9 h-9 rounded-full bg-blue-100 flex items-center justify-center mr-2">
                  <img src="/images/logo.png" alt="logo" className="w-full h-full" />
                </div>
                <span className="font-bold text-gray-900">애드모어 운영팀</span>
              </div>
              <button onClick={() => setChatOpen(false)} className="text-gray-400 hover:text-gray-700 text-2xl">×</button>
            </div>
            {/* 채팅 메시지 영역 */}
            <div className="flex-1 overflow-y-auto px-4 py-3 bg-gray-50">
              {messages.map((msg, idx) => (
                <div key={idx} className={`mb-3 flex ${msg.from === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`rounded-xl px-4 py-2 text-sm whitespace-pre-line ${msg.from === 'user' ? 'bg-blue-600 text-white' : 'bg-white border text-gray-800'}`}>{msg.text}</div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            {/* 입력창 */}
            <form className="flex items-center border-t px-3 py-2 gap-2" onSubmit={e => { e.preventDefault(); handleSend(); }}>
              <input
                type="text"
                className="flex-1 px-3 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                placeholder="메시지를 입력해 주세요."
                value={input}
                onChange={e => setInput(e.target.value)}
                autoFocus
              />
              <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-md font-semibold text-sm hover:bg-blue-700 transition">전송</button>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatWidget;
